SELECT ep.SEQ, ep.RESUME_SEQ, ep.PARAM_TYPE, ep.CODE_NO, ep.CODE_NAME, ep.FORMULA, (SELECT CODE_NAME FROM EVS_FORMULA WHERE SEQ = ep.FORMULA) FORMULA_NAME, ep.REMARK, ep.ACTIVITY, TO_CHAR(ep.ORDERNO) AS ORDER_NO, ep.START_STEP, GET_CODE_NAME(ep.START_STEP,#{lang, jdbcType=VARCHAR}) START_STEP_NAME, ep.LIST_TYPE, TO_CHAR(ep.EVS_SCORE) AS EVS_SCORE, TO_CHAR(ep.CREATE_DATE, 'YYYY-MM-DD HH24:MI:SS') AS CREATE_DATE, GET_UPDATED_INFO(ep.CREATED_BY) || ' ' || ep.CREATED_IP AS CREATED_BY, TO_CHAR(ep.UPDATE_DATE, 'YYYY-MM-DD HH24:MI') AS UPDATE_DATE, GET_UPDATED_INFO(ep.UPDATED_BY) || ' ' || ep.UPDATED_IP AS UPDATED_BY FROM EVS_PARAM ep WHERE ACTIVITY != 2
AND ep.RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
AND ep.PARAM_TYPE = #{paramType, jdbcType=VARCHAR}
ORDER BY TO_NUMBER(ep.SEQ)

mapper.delete:
UPDATE EVS_PARAM
SET UPDATE_DATE = SYSDATE,
    UPDATED_BY = #{adminID, jdbcType=VARCHAR},
    ACTIVITY = 2,
    UPDATED_IP = #{adminIP, jdbcType=VARCHAR}
WHERE SEQ     = #{seq,    jdbcType=VARCHAR}
